"""
Atomic write operations for session integrity and data safety.
Prevents data corruption from interrupted writes and provides rollback mechanisms.
"""
import json
import os
import shutil
import tempfile
import time
from pathlib import Path
from typing import Any, Dict, Optional, List
from contextlib import contextmanager
import logging

logger = logging.getLogger(__name__)

class AtomicWriteError(Exception):
    """Raised when atomic write operations fail"""
    pass

class AtomicWriter:
    """
    Provides atomic write operations with backup and recovery mechanisms.
    Ensures data integrity through temporary writes and atomic moves.
    """

    def __init__(self, backup_dir: Optional[str] = None):
        """Initialize atomic writer with optional backup directory"""
        self.backup_dir = Path(backup_dir) if backup_dir else None
        if self.backup_dir:
            self.backup_dir.mkdir(parents=True, exist_ok=True)

    def write_json_atomic(self, file_path: str, data: Any, backup: bool = True) -> bool:
        """
        Atomically write JSON data to file with optional backup.

        Args:
            file_path: Target file path
            data: Data to write (will be JSON serialized)
            backup: Whether to create backup before writing

        Returns:
            True if successful, False otherwise
        """
        target_path = Path(file_path)

        try:
            # Create backup if requested and file exists
            if backup and target_path.exists() and self.backup_dir:
                self._create_backup(target_path)

            # Write to temporary file first
            with tempfile.NamedTemporaryFile(
                mode='w',
                dir=target_path.parent,
                delete=False,
                suffix='.tmp'
            ) as temp_file:
                json.dump(data, temp_file, indent=2)
                temp_file.flush()
                os.fsync(temp_file.fileno())  # Force write to disk
                temp_path = temp_file.name

            # Atomic move to final location
            shutil.move(temp_path, target_path)
            logger.debug(f"Atomically wrote JSON to {file_path}")
            return True

        except Exception as e:
            logger.error(f"Atomic write failed for {file_path}: {e}")
            # Clean up temp file if it exists
            if 'temp_path' in locals() and os.path.exists(temp_path):
                try:
                    os.unlink(temp_path)
                except:
                    pass
            return False

    def append_jsonl_atomic(self, file_path: str, data: Dict, backup: bool = True) -> bool:
        """
        Atomically append JSON line to JSONL file.

        Args:
            file_path: Target JSONL file path
            data: Data to append as JSON line
            backup: Whether to create backup before writing

        Returns:
            True if successful, False otherwise
        """
        target_path = Path(file_path)

        try:
            # Create backup if requested and file exists
            if backup and target_path.exists() and self.backup_dir:
                self._create_backup(target_path)

            # Read existing content if file exists
            existing_lines = []
            if target_path.exists():
                with open(target_path, 'r') as f:
                    existing_lines = f.readlines()

            # Write all content to temporary file
            with tempfile.NamedTemporaryFile(
                mode='w',
                dir=target_path.parent,
                delete=False,
                suffix='.tmp'
            ) as temp_file:
                # Write existing lines
                for line in existing_lines:
                    temp_file.write(line)

                # Append new line
                temp_file.write(json.dumps(data) + '\n')
                temp_file.flush()
                os.fsync(temp_file.fileno())
                temp_path = temp_file.name

            # Atomic move to final location
            shutil.move(temp_path, target_path)
            logger.debug(f"Atomically appended to JSONL {file_path}")
            return True

        except Exception as e:
            logger.error(f"Atomic append failed for {file_path}: {e}")
            # Clean up temp file if it exists
            if 'temp_path' in locals() and os.path.exists(temp_path):
                try:
                    os.unlink(temp_path)
                except:
                    pass
            return False

    def _create_backup(self, file_path) -> bool:
        """Create timestamped backup of file"""
        if not self.backup_dir:
            return False

        try:
            # Convert to Path if it's a string
            file_path = Path(file_path) if not isinstance(file_path, Path) else file_path

            timestamp = int(time.time())
            backup_name = f"{file_path.stem}_{timestamp}{file_path.suffix}"
            backup_path = self.backup_dir / backup_name

            shutil.copy2(file_path, backup_path)
            logger.debug(f"Created backup: {backup_path}")
            return True

        except Exception as e:
            logger.error(f"Backup creation failed for {file_path}: {e}")
            return False

    def restore_from_backup(self, file_path: str, backup_timestamp: Optional[int] = None) -> bool:
        """
        Restore file from backup.

        Args:
            file_path: Target file to restore
            backup_timestamp: Specific backup timestamp, or None for latest

        Returns:
            True if restoration successful
        """
        if not self.backup_dir:
            logger.error("No backup directory configured")
            return False

        target_path = Path(file_path)
        backup_pattern = f"{target_path.stem}_*{target_path.suffix}"

        try:
            # Find backup files
            backup_files = list(self.backup_dir.glob(backup_pattern))
            if not backup_files:
                logger.error(f"No backups found for {file_path}")
                return False

            # Select backup file
            if backup_timestamp:
                backup_file = self.backup_dir / f"{target_path.stem}_{backup_timestamp}{target_path.suffix}"
                if not backup_file.exists():
                    logger.error(f"Backup with timestamp {backup_timestamp} not found")
                    return False
            else:
                # Use latest backup (highest timestamp)
                backup_file = max(backup_files, key=lambda p: p.stat().st_mtime)

            # Restore file atomically
            return self._copy_file_atomic(backup_file, target_path)

        except Exception as e:
            logger.error(f"Backup restoration failed: {e}")
            return False

    def _copy_file_atomic(self, source: Path, target: Path) -> bool:
        """Copy file atomically using temporary intermediate"""
        try:
            with tempfile.NamedTemporaryFile(
                dir=target.parent,
                delete=False,
                suffix='.tmp'
            ) as temp_file:
                temp_path = temp_file.name

            shutil.copy2(source, temp_path)
            shutil.move(temp_path, target)
            logger.debug(f"Atomically copied {source} to {target}")
            return True

        except Exception as e:
            logger.error(f"Atomic copy failed: {e}")
            if os.path.exists(temp_path):
                try:
                    os.unlink(temp_path)
                except:
                    pass
            return False

    def cleanup_old_backups(self, keep_count: int = 10) -> int:
        """
        Clean up old backup files, keeping only the most recent ones.

        Args:
            keep_count: Number of recent backups to keep per file

        Returns:
            Number of backups deleted
        """
        if not self.backup_dir:
            return 0

        deleted_count = 0

        try:
            # Group backup files by original filename
            backup_groups = {}
            for backup_file in self.backup_dir.glob("*_[0-9]*.*"):
                # Extract original filename by removing timestamp suffix
                parts = backup_file.stem.split('_')
                if len(parts) >= 2 and parts[-1].isdigit():
                    original_name = '_'.join(parts[:-1]) + backup_file.suffix
                    if original_name not in backup_groups:
                        backup_groups[original_name] = []
                    backup_groups[original_name].append(backup_file)

            # Clean up each group
            for original_name, backup_files in backup_groups.items():
                # Sort by modification time (newest first)
                backup_files.sort(key=lambda p: p.stat().st_mtime, reverse=True)

                # Delete excess backups
                for old_backup in backup_files[keep_count:]:
                    try:
                        old_backup.unlink()
                        deleted_count += 1
                        logger.debug(f"Deleted old backup: {old_backup}")
                    except Exception as e:
                        logger.error(f"Failed to delete backup {old_backup}: {e}")

            logger.info(f"Cleaned up {deleted_count} old backup files")
            return deleted_count

        except Exception as e:
            logger.error(f"Backup cleanup failed: {e}")
            return deleted_count

    def list_backups(self, file_path: Optional[str] = None) -> List[Dict[str, Any]]:
        """
        List available backups.

        Args:
            file_path: Specific file to list backups for, or None for all

        Returns:
            List of backup info dictionaries
        """
        if not self.backup_dir:
            return []

        backups = []

        try:
            if file_path:
                # List backups for specific file
                target_path = Path(file_path)
                backup_pattern = f"{target_path.stem}_*{target_path.suffix}"
                backup_files = list(self.backup_dir.glob(backup_pattern))
            else:
                # List all backups
                backup_files = [f for f in self.backup_dir.iterdir() if f.is_file()]

            for backup_file in backup_files:
                # Extract timestamp from filename
                parts = backup_file.stem.split('_')
                timestamp = None
                if parts and parts[-1].isdigit():
                    timestamp = int(parts[-1])

                backup_info = {
                    'file_path': str(backup_file),
                    'original_file': file_path if file_path else '_'.join(parts[:-1]) + backup_file.suffix,
                    'timestamp': timestamp,
                    'created_at': time.ctime(backup_file.stat().st_mtime),
                    'size_bytes': backup_file.stat().st_size
                }
                backups.append(backup_info)

            # Sort by timestamp (newest first)
            backups.sort(key=lambda b: b['timestamp'] or 0, reverse=True)
            return backups

        except Exception as e:
            logger.error(f"Failed to list backups: {e}")
            return []

@contextmanager
def atomic_session_write(session_manager, backup_dir: Optional[str] = None):
    """
    Context manager for atomic session operations with automatic rollback.

    Usage:
        with atomic_session_write(session_manager) as writer:
            writer.write_json_atomic("session.json", session_data)
            writer.append_jsonl_atomic("logs.jsonl", log_entry)
    """
    writer = AtomicWriter(backup_dir)
    rollback_operations = []

    try:
        # Store original write methods
        original_write_json = getattr(session_manager, '_write_json', None)
        original_append_jsonl = getattr(session_manager, '_append_jsonl', None)

        # Replace with atomic versions
        def atomic_write_json(file_path: str, data: Any) -> bool:
            success = writer.write_json_atomic(file_path, data)
            if success:
                rollback_operations.append(('restore', file_path))
            return success

        def atomic_append_jsonl(file_path: str, data: Dict) -> bool:
            success = writer.append_jsonl_atomic(file_path, data)
            if success:
                rollback_operations.append(('restore', file_path))
            return success

        session_manager._write_json = atomic_write_json
        session_manager._append_jsonl = atomic_append_jsonl

        yield writer

        # If we get here, all operations succeeded
        logger.debug(f"Atomic session operations completed successfully")

    except Exception as e:
        logger.error(f"Atomic session operations failed: {e}")

        # Attempt to rollback changes
        for operation, file_path in reversed(rollback_operations):
            if operation == 'restore':
                try:
                    writer.restore_from_backup(file_path)
                    logger.debug(f"Rolled back {file_path}")
                except Exception as rollback_error:
                    logger.error(f"Rollback failed for {file_path}: {rollback_error}")

        raise

    finally:
        # Restore original methods
        if original_write_json:
            session_manager._write_json = original_write_json
        if original_append_jsonl:
            session_manager._append_jsonl = original_append_jsonl

# Global atomic writer instance
global_atomic_writer = AtomicWriter()